  1→/**
  2→ * ContractRepository - CRUD operations for Contract model
  3→ *
  4→ * Provides typed methods for Contract queries with soft-delete support.
  5→ * Handles contract versions and signers.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Contract,
 11→  ContractVersion,
 12→  ContractSigner,
 13→  Prisma,
 14→  Deal,
 15→} from '@prisma/client';
 16→import { randomUUID } from 'node:crypto';
 17→
 18→/**
 19→ * Contract creation input type
 20→ */
 21→export type ContractCreateInput = Omit<Prisma.ContractUncheckedCreateInput, 'id' | 'number' | 'createdAt' | 'updatedAt'>;
 22→
 23→/**
 24→ * Contract update input type
 25→ */
 26→export type ContractUpdateInput = Prisma.ContractUncheckedUpdateInput;
 27→
 28→/**
 29→ * Contract findMany params type
 30→ */
 31→export type ContractFindManyParams = {
 32→  where?: Prisma.ContractWhereInput;
 33→  orderBy?: Prisma.ContractOrderByWithRelationInput;
 34→  skip?: number;
 35→  take?: number;
 36→  include?: Prisma.ContractInclude;
 37→};
 38→
 39→/**
 40→ * Repository for Contract CRUD operations
 41→ */
 42→export class ContractRepository {
 43→  /**
 44→   * Generate contract number in format Д-YYYY-NNNNN
 45→   */
 46→  private generateNumber(): string {
 47→    const year = new Date().getFullYear();
 48→    const random = Math.floor(Math.random() * 99999).toString().padStart(5, '0');
 49→    return `Д-${year}-${random}`;
 50→  }
 51→
 52→  /**
 53→   * Find many contracts with optional filtering
 54→   * Automatically filters out soft-deleted records
 55→   */
 56→  async findMany(params?: ContractFindManyParams): Promise<Contract[]> {
 57→    const { where, ...rest } = params ?? {};
 58→
 59→    return prisma.contract.findMany({
 60→      ...rest,
 61→      where: {
 62→        ...where,
 63→        deletedAt: null, // Always exclude soft-deleted
 64→      },
 65→    });
 66→  }
 67→
 68→  /**
 69→   * Find a single contract by ID
 70→   * Returns null if not found or soft-deleted
 71→   */
 72→  async findUnique(
 73→    id: string,
 74→    include?: Prisma.ContractInclude
 75→  ): Promise<Contract | null> {
 76→    return prisma.contract.findFirst({
 77→      where: { id, deletedAt: null },
 78→      include,
 79→    });
 80→  }
 81→
 82→  /**
 83→   * Find contracts by contact
 84→   */
 85→  async findByContact(contactId: string): Promise<Contract[]> {
 86→    return this.findMany({
 87→      where: { contactId },
 88→      orderBy: { createdAt: 'desc' },
 89→    });
 90→  }
 91→
 92→  /**
 93→   * Find contract by deal ID
 94→   */
 95→  async findByDeal(dealId: string): Promise<Contract | null> {
 96→    return prisma.contract.findFirst({
 97→      where: { dealId, deletedAt: null },
 98→    });
 99→  }
100→
101→  /**
102→   * Create a new contract
103→   * Generates UUID, number, and timestamps if not provided
104→   */
105→  async create(data: ContractCreateInput): Promise<Contract> {
106→    const now = new Date();
107→
108→    return prisma.contract.create({
109→      data: {
110→        ...data,
111→        id: data.id ?? randomUUID(),
112→        number: data.number ?? this.generateNumber(),
113→        createdAt: data.createdAt ?? now,
114→        updatedAt: data.updatedAt ?? now,
115→      },
116→    });
117→  }
118→
119→  /**
120→   * Update an existing contract
121→   * Throws RecordNotFound if contract doesn't exist or is soft-deleted
122→   */
123→  async update(
124→    id: string,
125→    data: ContractUpdateInput
126→  ): Promise<Contract> {
127→    // Verify contract exists and not deleted
128→    const existing = await this.findUnique(id);
129→    if (!existing) {
130→      throw new Error(`Contract with id ${id} not found`);
131→    }
132→
133→    return prisma.contract.update({
134→      where: { id },
135→      data: {
136→        ...data,
137→        updatedAt: new Date(),
138→      },
139→    });
140→  }
141→
142→  /**
143→   * Soft delete a contract by setting deletedAt timestamp
144→   */
145→  async softDelete(id: string): Promise<Contract> {
146→    const existing = await this.findUnique(id);
147→    if (!existing) {
148→      throw new Error(`Contract with id ${id} not found`);
149→    }
150→
151→    return prisma.contract.update({
152→      where: { id },
153→      data: { deletedAt: new Date() },
154→    });
155→  }
156→
157→  /**
158→   * Count contracts matching criteria (excluding soft-deleted)
159→   */
160→  async count(where?: Prisma.ContractWhereInput): Promise<number> {
161→    return prisma.contract.count({
162→      where: {
163→        ...where,
164→        deletedAt: null,
165→      },
166→    });
167→  }
168→
169→  /**
170→   * Add a version to a contract
171→   */
172→  async addVersion(
173→    contractId: string,
174→    contentMd: string,
175→    createdBy: string,
176→    generatedPdfFileId?: string
177→  ): Promise<ContractVersion> {
178→    // Get next version number
179→    const latestVersion = await prisma.contractVersion.findFirst({
180→      where: { contractId },
181→      orderBy: { version: 'desc' },
182→    });
183→
184→    const nextVersion = (latestVersion?.version ?? 0) + 1;
185→
186→    return prisma.contractVersion.create({
187→      data: {
188→        id: randomUUID(),
189→        contractId,
190→        version: nextVersion,
191→        contentMd,
192→        generatedPdfFileId,
193→        createdBy,
194→        createdAt: new Date(),
195→      },
196→    });
197→  }
198→
199→  /**
200→   * Get all versions of a contract
201→   */
202→  async getVersions(contractId: string): Promise<ContractVersion[]> {
203→    return prisma.contractVersion.findMany({
204→      where: { contractId },
205→      orderBy: { version: 'desc' },
206→    });
207→  }
208→
209→  /**
210→   * Add a signer to a contract
211→   */
212→  async addSigner(
213→    contractId: string,
214→    name: string,
215→    position?: string,
216→    signatureFileId?: string
217→  ): Promise<ContractSigner> {
218→    return prisma.contractSigner.create({
219→      data: {
220→        id: randomUUID(),
221→        contractId,
222→        name,
223→        position,
224→        signatureFileId,
225→      },
226→    });
227→  }
228→
229→  /**
230→   * Get all signers of a contract
231→   */
232→  async getSigners(contractId: string): Promise<ContractSigner[]> {
233→    return prisma.contractSigner.findMany({
234→      where: { contractId },
235→      orderBy: { id: 'asc' },
236→    });
237→  }
238→
239→  /**
240→   * Convert a deal to a contract
241→   * Creates a contract from deal data and links them
242→   * Uses transaction to ensure atomic bidirectional link creation
243→   */
244→  async convertFromDeal(
245→    dealId: string,
246→    additionalData?: Partial<ContractCreateInput>
247→  ): Promise<Contract> {
248→    return prisma.$transaction(async (tx) => {
249→      const deal = await tx.deal.findFirst({
250→        where: { id: dealId, deletedAt: null },
251→        include: { contact: true },
252→      });
253→
254→      if (!deal) {
255→        throw new Error(`Deal with id ${dealId} not found`);
256→      }
257→
258→      // Check if contract already exists (use transaction client for consistency)
259→      const existing = await tx.contract.findFirst({
260→        where: { dealId, deletedAt: null },
261→      });
262→      if (existing) {
263→        throw new Error(`Contract already exists for deal ${dealId}`);
264→      }
265→
266→      // Generate contract data
267→      const now = new Date();
268→      const contractId = randomUUID();
269→      const contractNumber = this.generateNumber();
270→
271→      // Create contract from deal (within transaction)
272→      const contract = await tx.contract.create({
273→        data: {
274→          id: contractId,
275→          dealId,
276→          contactId: deal.contactId || undefined,
277→          title: `Договор: ${deal.title}`,
278→          amount: deal.amount,
279→          currency: deal.currency,
280→          description: deal.description || undefined,
281→          status: 'draft',
282→          number: contractNumber,
283→          createdAt: now,
284→          updatedAt: now,
285→          ...additionalData,
286→        },
287→      });
288→
289→      // Update deal with contractId (within same transaction)
290→      await tx.deal.update({
291→        where: { id: dealId },
292→        data: { contractId: contract.id },
293→      });
294→
295→      return contract;
296→    });
297→  }
298→}
299→
300→/**
301→ * Singleton instance for use across the application
302→ */
303→export const contracts = new ContractRepository();
304→
305→export default contracts;
306→

  1→/**
  2→ * ContactRepository tests
  3→ *
  4→ * Uses tsx for test execution. Creates a test contact in dev.db.
  5→ */
  6→
  7→import { describe, it } from 'node:test';
  8→import assert from 'node:assert';
  9→import { contacts } from './contacts.js';
 10→import { prisma } from './prisma.js';
 11→
 12→describe('ContactRepository', { concurrency: false }, () => {
 13→  // Track created test contact for cleanup
 14→  let testContactId: string;
 15→
 16→  it('should create a new contact', async () => {
 17→    // Ensure clean state before first test
 18→    await prisma.contact.deleteMany({
 19→      where: { email: 'test@example.com' },
 20→    });
 21→
 22→    const contact = await contacts.create({
 23→      type: 'person',
 24→      firstName: 'Test',
 25→      lastName: 'User',
 26→      email: 'test@example.com',
 27→      phone: '+79991234567',
 28→      status: 'active',
 29→      tags: ['test', 'tsx-test'],
 30→    });
 31→
 32→    assert.ok(contact, 'Contact should be created');
 33→    assert.ok(contact.id, 'Contact should have an ID');
 34→    assert.strictEqual(contact.email, 'test@example.com');
 35→    assert.strictEqual(contact.type, 'person');
 36→    testContactId = contact.id;
 37→  });
 38→
 39→  it('should find contact by ID', async () => {
 40→    const contact = await contacts.findUnique(testContactId);
 41→    assert.ok(contact, 'Contact should be found');
 42→    assert.strictEqual(contact?.id, testContactId);
 43→    assert.strictEqual(contact?.email, 'test@example.com');
 44→  });
 45→
 46→  it('should find contact by email', async () => {
 47→    const contact = await contacts.findByEmail('test@example.com');
 48→    assert.ok(contact, 'Contact should be found by email');
 49→    assert.strictEqual(contact?.id, testContactId);
 50→  });
 51→
 52→  it('should find many contacts', async () => {
 53→    const list = await contacts.findMany({
 54→      where: { type: 'person' },
 55→      orderBy: { createdAt: 'desc' },
 56→    });
 57→    assert.ok(Array.isArray(list), 'Result should be an array');
 58→    assert.ok(list.length > 0, 'Array should have items');
 59→    assert.strictEqual(list[0].email, 'test@example.com');
 60→  });
 61→
 62→  it('should update a contact', async () => {
 63→    const updated = await contacts.update(testContactId, {
 64→      phone: '+79997654321',
 65→      notes: 'Updated via test',
 66→    });
 67→    assert.strictEqual(updated.phone, '+79997654321');
 68→    assert.strictEqual(updated.notes, 'Updated via test');
 69→  });
 70→
 71→  it('should soft delete a contact', async () => {
 72→    const deleted = await contacts.softDelete(testContactId);
 73→    assert.ok(deleted.deletedAt, 'deletedAt should be set');
 74→
 75→    // Should not be found via normal queries
 76→    const notFound = await contacts.findUnique(testContactId);
 77→    assert.strictEqual(notFound, null, 'Soft-deleted contact should not be found');
 78→
 79→    // But should still exist in database
 80→    const stillExists = await prisma.contact.findUnique({
 81→      where: { id: testContactId },
 82→    });
 83→    assert.ok(stillExists, 'Contact should still exist in DB');
 84→    assert.ok(stillExists?.deletedAt, 'Contact should have deletedAt set');
 85→  });
 86→
 87→  it('should check email existence', async () => {
 88→    // Create fresh contact for existence test
 89→    const fresh = await contacts.create({
 90→      type: 'person',
 91→      firstName: 'Fresh',
 92→      lastName: 'Test',
 93→      email: 'freshtest@example.com',
 94→    });
 95→
 96→    const exists = await contacts.existsByEmail('freshtest@example.com');
 97→    assert.strictEqual(exists, true, 'Email should exist');
 98→
 99→    const notExists = await contacts.existsByEmail('nonexistent@example.com');
100→    assert.strictEqual(notExists, false, 'Nonexistent email should not exist');
101→
102→    // Cleanup
103→    await prisma.contact.delete({ where: { id: fresh.id } });
104→  });
105→
106→  it('should count contacts', async () => {
107→    const count = await contacts.count();
108→    assert.strictEqual(typeof count, 'number', 'Count should be a number');
109→    assert.ok(count >= 0, 'Count should be non-negative');
110→  });
111→
112→  // Final cleanup
113→  it('cleanup test data', async () => {
114→    if (testContactId) {
115→      await prisma.contact.deleteMany({
116→        where: { id: testContactId },
117→      });
118→    }
119→    await prisma.$disconnect();
120→  });
121→});
